  1→/**
  2→ * Orchestrates the full sync process: metadata extraction, body HTML,
  3→ * image upload, and content push to dotCMS.
  4→ */
  5→var SyncEngine = {
  6→
  7→  PROP_SYNC_LOG: 'dotcms_sync_log',
  8→
  9→  /**
 10→   * Main sync entry point.
 11→   * @param {Object} options - { contentType, siteId, folderPath, bodyField, languageId, publishMode }
 12→   * @returns {Object} - sync result with status, message, failures
 13→   */
 14→  sync: function (options) {
 15→    var startTime = new Date();
 16→    var s = SettingsService.getAll();
 17→
 18→    if (!s.hostUrl || !s.apiToken) {
 19→      return this._fail('dotCMS host URL and API token are required. Configure in Settings tab.');
 20→    }
 21→
 22→    var result = {
 23→      status: 'success',
 24→      message: '',
 25→      failures: [],
 26→      contentIdentifier: '',
 27→      imagesUploaded: 0,
 28→      imagesSkipped: 0,
 29→      imagesFailed: 0
 30→    };
 31→
 32→    try {
 33→      // Step 1: Extract metadata fields from the table
 34→      var metadataFields = DocParser.extractMetadataFields();
 35→
 36→      // Step 2: Get body HTML
 37→      var bodyHtml = DocParser.getBodyHtml();
 38→
 39→      // Step 3: Get images from the document
 40→      var images = DocParser.getImages();
 41→
 42→      // Step 4: Upload images (with deduplication)
 43→      var imgResult = { uploaded: [], failed: [], imageMap: {} };
 44→      if (images.length > 0) {
 45→        imgResult = ImageHandler.uploadImages(
 46→          images,
 47→          s.hostUrl,
 48→          s.apiToken,
 49→          options.siteId,
 50→          options.folderPath || '',
 51→          options.languageId || 1
 52→        );
 53→      }
 54→
 55→      // Step 5: Replace image URLs in body HTML
 56→      if (images.length > 0) {
 57→        bodyHtml = ImageHandler.replaceImageUrls(bodyHtml, images, imgResult.imageMap, s.hostUrl);
 58→      }
 59→
 60→      // Step 6: Build the contentlet payload from metadata table
 61→      // The metadata table is the single source of truth for all field values.
 62→      // Sidebar options are fallbacks only.
 63→      var contentlet = {};
 64→      var existingId = '';
 65→
 66→      for (var i = 0; i < metadataFields.length; i++) {
 67→        var mf = metadataFields[i];
 68→        if (!mf.variable) continue;
 69→
 70→        if (mf.variable === 'identifier') {
 71→          if (mf.value) existingId = mf.value;
 72→          continue; // identifier is handled separately
 73→        }
 74→
 75→        if (mf.value) {
 76→          contentlet[mf.variable] = mf.value;
 77→        }
 78→      }
 79→
 80→      // Apply sidebar fallbacks for required fields if not in table
 81→      if (!contentlet.contentType) contentlet.contentType = options.contentType;
 82→      if (!contentlet.host) contentlet.host = options.siteId;
 83→      if (!contentlet.languageId) contentlet.languageId = options.languageId || 1;
 84→
 85→      // Add body content to the designated body field
 86→      contentlet[options.bodyField || 'body'] = bodyHtml;
 87→
 88→      if (existingId) {
 89→        contentlet.identifier = existingId;
 90→      }
 91→
 92→      // Step 7: Fire workflow action (SAVE or PUBLISH)
 93→      var action = options.publishMode === 'PUBLISH' ? 'PUBLISH' : 'EDIT';
 94→      var entity = DotCMSApi.fireWorkflow(s.hostUrl, s.apiToken, action, contentlet);
 95→
 96→      // Debug: log what fireWorkflow returned
 97→      Logger.log('entity keys: ' + Object.keys(entity).join(', '));
 98→      Logger.log('entity.identifier: ' + entity.identifier);
 99→      Logger.log('entity JSON (first 500): ' + JSON.stringify(entity).substring(0, 500));
100→
101→      // Write the identifier back to the metadata table so subsequent syncs update
102→      if (entity.identifier) {
103→        DocParser.updateMetadataField('identifier', entity.identifier);
104→        result.contentIdentifier = entity.identifier;
105→      }
106→
107→      // Compile results
108→      result.imagesUploaded = imgResult.uploaded.filter(function (u) { return !u.skipped; }).length;
109→      result.imagesSkipped = imgResult.uploaded.filter(function (u) { return u.skipped; }).length;
110→      result.imagesFailed = imgResult.failed.length;
111→      result.failures = imgResult.failed;
112→
