  1→/**
  2→ * Document parsing: metadata table detection, field extraction, body HTML export.
  3→ */
  4→var DocParser = {
  5→
  6→  MARKER_FIELD: 'Field',
  7→  MARKER_VALUE: 'Value',
  8→
  9→  /**
 10→   * Find the metadata table by scanning for a table whose first row
 11→   * contains 'Field' and 'Value' headers.
 12→   * Returns {tableIndex, table} or null.
 13→   */
 14→  findMetadataTable: function () {
 15→    var doc = DocumentApp.getActiveDocument();
 16→    var body = doc.getBody();
 17→    var numChildren = body.getNumChildren();
 18→
 19→    for (var i = 0; i < numChildren; i++) {
 20→      var child = body.getChild(i);
 21→      if (child.getType() !== DocumentApp.ElementType.TABLE) continue;
 22→
 23→      var table = child.asTable();
 24→      if (table.getNumRows() < 1 || table.getRow(0).getNumCells() < 2) continue;
 25→
 26→      var h1 = table.getRow(0).getCell(0).getText().trim();
 27→      var h2 = table.getRow(0).getCell(1).getText().trim();
 28→
 29→      if (h1 === this.MARKER_FIELD && h2 === this.MARKER_VALUE) {
 30→        return { tableIndex: i, table: table };
 31→      }
 32→    }
 33→    return null;
 34→  },
 35→
 36→  /**
 37→   * Extract field/value pairs from the metadata table (skipping header row).
 38→   */
 39→  extractMetadataFields: function () {
 40→    var result = this.findMetadataTable();
 41→    if (!result) return [];
 42→
 43→    var table = result.table;
 44→    var fields = [];
 45→    for (var r = 1; r < table.getNumRows(); r++) {
 46→      var row = table.getRow(r);
 47→      if (row.getNumCells() < 2) continue;
 48→      var fieldVar = row.getCell(0).getText().trim();
 49→      var fieldVal = row.getCell(1).getText().trim();
 50→      if (fieldVar) {
 51→        fields.push({ variable: fieldVar, value: fieldVal });
 52→      }
 53→    }
 54→    return fields;
 55→  },
 56→
 57→  /**
 58→   * Generate the metadata table at the top of the document.
 59→   * Only includes required fields (and non-layout, non-relationship fields get free text;
 60→   * selects/booleans get dropdown notation).
 61→   */
 62→  IDENTIFIER_FIELD: 'identifier',
 63→
 64→  /**
 65→   * Generate or merge the metadata table.
 66→   * If a table already exists, only add missing required fields (preserving existing values).
 67→   * If no table exists, create a new one.
 68→   */
 69→  generateMetadataTable: function (fields) {
 70→    var doc = DocumentApp.getActiveDocument();
 71→    var body = doc.getBody();
 72→
 73→    var requiredFields = fields.filter(function (f) {
 74→      return f.required;
 75→    });
 76→
 77→    var existing = this.findMetadataTable();
 78→
 79→    if (existing) {
 80→      // Merge: add rows for fields not already in the table
 81→      var table = existing.table;
 82→      var existingVars = {};
 83→      for (var r = 1; r < table.getNumRows(); r++) {
 84→        var varName = table.getRow(r).getCell(0).getText().trim();
 85→        if (varName) existingVars[varName] = true;
 86→      }
 87→
 88→      // Ensure identifier row exists
 89→      if (!existingVars['identifier']) {
 90→        var idRow = table.appendTableRow();
 91→        idRow.appendTableCell('identifier');
 92→        idRow.appendTableCell('');
 93→      }
 94→
 95→      // Ensure contentType row exists
 96→      if (!existingVars['contentType']) {
 97→        var ctRow = table.appendTableRow();
 98→        ctRow.appendTableCell('contentType');
 99→        ctRow.appendTableCell('');
100→      }
101→
102→      // Ensure default rows exist
103→      var defaults = ['host', 'folder', 'languageId'];
104→      for (var d = 0; d < defaults.length; d++) {
105→        if (!existingVars[defaults[d]]) {
106→          var defRow = table.appendTableRow();
107→          defRow.appendTableCell(defaults[d]);
108→          defRow.appendTableCell('');
109→        }
110→      }
111→
112→      // Add missing required fields
113→      for (var i = 0; i < requiredFields.length; i++) {
114→        if (!existingVars[requiredFields[i].variable]) {
115→          var newRow = table.appendTableRow();
116→          newRow.appendTableCell(requiredFields[i].variable);
117→          newRow.appendTableCell('');
118→        }
119→      }
120→    } else {
121→      // Create new table
122→      var table = body.insertTable(0, this._buildTableCells(requiredFields));
123→
124→      // Style header row
125→      var headerRow = table.getRow(0);
126→      headerRow.getCell(0).setText(this.MARKER_FIELD).setAttributes(this._boldStyle());
127→      headerRow.getCell(1).setText(this.MARKER_VALUE).setAttributes(this._boldStyle());
128→
129→      // Insert a paragraph after the table for body content
130→      body.insertParagraph(1, '');
131→    }
132→
133→    return requiredFields;
134→  },
135→
136→  /**
137→   * Update a specific field's value cell in the metadata table.
138→   * Called from sidebar when user selects a value from a dropdown or lookup.
139→   */
140→  updateMetadataField: function (fieldVariable, value) {
141→    var result = this.findMetadataTable();
142→    if (!result) return;
143→
144→    var table = result.table;
145→    for (var r = 1; r < table.getNumRows(); r++) {
146→      var row = table.getRow(r);
147→      if (row.getNumCells() < 2) continue;
148→      if (row.getCell(0).getText().trim() === fieldVariable) {
149→        row.getCell(1).setText(value);
150→        return;
151→      }
152→    }
153→  },
154→
155→  _buildTableCells: function (requiredFields) {
156→    var cells = [['Field', 'Value'], ['identifier', ''], ['contentType', ''], ['host', ''], ['folder', ''], ['languageId', '']];
157→    for (var i = 0; i < requiredFields.length; i++) {
158→      cells.push([requiredFields[i].variable, '']);
159→    }
160→    return cells;
161→  },
162→
163→  _getFieldHint: function (field) {
164→    // Select, boolean, and relationship fields are handled by the sidebar Field Editor.
165→    // No hints needed in the table — the sidebar writes values directly.
166→    return '';
167→  },
168→
169→  _boldStyle: function () {
170→    var style = {};
171→    style[DocumentApp.Attribute.BOLD] = true;
172→    return style;
173→  },
174→
175→  /**
176→   * Export the body content (everything outside the metadata table) as clean HTML.
177→   * Builds HTML directly from DocumentApp elements — no external API needed.
178→   */
179→  getBodyHtml: function () {
180→    var doc = DocumentApp.getActiveDocument();
181→    var body = doc.getBody();
182→    var metaTable = this.findMetadataTable();
183→    var metaTableIndex = metaTable ? metaTable.tableIndex : -1;
184→    var numChildren = body.getNumChildren();
185→    var html = '';
186→
187→    for (var i = 0; i < numChildren; i++) {
188→      if (i === metaTableIndex) continue;
189→      html += this._elementToHtml(body.getChild(i));
190→    }
191→
192→    return html.trim();
193→  },
194→
195→  /**
196→   * Convert a DocumentApp element to HTML.
197→   */
198→  _elementToHtml: function (element) {
199→    var type = element.getType();
200→
201→    if (type === DocumentApp.ElementType.PARAGRAPH) {
202→      return this._paragraphToHtml(element.asParagraph());
203→    }
204→    if (type === DocumentApp.ElementType.LIST_ITEM) {
205→      return this._listItemToHtml(element.asListItem());
206→    }
207→    if (type === DocumentApp.ElementType.TABLE) {
208→      return this._tableToHtml(element.asTable());
209→    }
210→    if (type === DocumentApp.ElementType.HORIZONTAL_RULE) {
211→      return '<hr>';
212→    }
213→
214→    // Fallback: extract text
215→    var text = element.asText ? element.asText().getText() : '';
216→    if (text) return '<p>' + this._escapeHtml(text) + '</p>';
217→    return '';
218→  },
219→
220→  _paragraphToHtml: function (para) {
221→    var heading = para.getHeading();
222→    var content = this._renderInlineContent(para);
223→    if (!content && heading === DocumentApp.ParagraphHeading.NORMAL) return '';
224→
225→    var tag = 'p';
226→    switch (heading) {
227→      case DocumentApp.ParagraphHeading.HEADING1: tag = 'h1'; break;
228→      case DocumentApp.ParagraphHeading.HEADING2: tag = 'h2'; break;
229→      case DocumentApp.ParagraphHeading.HEADING3: tag = 'h3'; break;
230→      case DocumentApp.ParagraphHeading.HEADING4: tag = 'h4'; break;
231→      case DocumentApp.ParagraphHeading.HEADING5: tag = 'h5'; break;
232→      case DocumentApp.ParagraphHeading.HEADING6: tag = 'h6'; break;
233→    }
234→    return '<' + tag + '>' + content + '</' + tag + '>';
235→  },
236→
237→  _listItemToHtml: function (item) {
238→    var glyph = item.getGlyphType();
239→    var content = this._renderInlineContent(item);
240→    // Simple list rendering — nested lists would need tracking state across calls
241→    var isOrdered = (glyph === DocumentApp.GlyphType.NUMBER ||
242→                     glyph === DocumentApp.GlyphType.LATIN_UPPER ||
243→                     glyph === DocumentApp.GlyphType.LATIN_LOWER ||
244→                     glyph === DocumentApp.GlyphType.ROMAN_UPPER ||
245→                     glyph === DocumentApp.GlyphType.ROMAN_LOWER);
246→    var tag = isOrdered ? 'ol' : 'ul';
247→    return '<' + tag + '><li>' + content + '</li></' + tag + '>';
248→  },
249→
250→  _tableToHtml: function (table) {
251→    var html = '<table>';
252→    for (var r = 0; r < table.getNumRows(); r++) {
253→      html += '<tr>';
254→      var row = table.getRow(r);
255→      for (var c = 0; c < row.getNumCells(); c++) {
256→        var cell = row.getCell(c);
257→        html += '<td>' + this._escapeHtml(cell.getText()) + '</td>';
258→      }
259→      html += '</tr>';
260→    }
261→    html += '</table>';
262→    return html;
263→  },
264→
265→  /**
266→   * Render inline content (text with formatting + inline images) from a paragraph or list item.
267→   */
268→  _renderInlineContent: function (element) {
269→    var html = '';
270→    var numChildren = element.getNumChildren();
271→
272→    for (var i = 0; i < numChildren; i++) {
273→      var child = element.getChild(i);
274→      var childType = child.getType();
275→
276→      if (childType === DocumentApp.ElementType.TEXT) {
277→        html += this._textToHtml(child.asText());
278→      } else if (childType === DocumentApp.ElementType.INLINE_IMAGE) {
279→        // Placeholder src — will be replaced by ImageHandler with dotAsset URLs
280→        html += '<img src="image_placeholder_' + i + '">';
281→      } else if (childType === DocumentApp.ElementType.INLINE_DRAWING) {
282→        html += '<img src="drawing_placeholder_' + i + '">';
283→      }
284→    }
285→    return html;
286→  },
287→
288→  /**
289→   * Convert a Text element to HTML, preserving bold, italic, underline, links.
290→   */
291→  _textToHtml: function (textEl) {
292→    var text = textEl.getText();
293→    if (!text) return '';
294→
295→    var html = '';
296→    var i = 0;
297→    while (i < text.length) {
298→      // Find runs of same formatting
299→      var bold = textEl.isBold(i);
300→      var italic = textEl.isItalic(i);
301→      var underline = textEl.isUnderline(i);
302→      var strikethrough = textEl.isStrikethrough(i);
303→      var link = textEl.getLinkUrl(i);
304→
305→      var j = i + 1;
306→      while (j < text.length &&
307→             textEl.isBold(j) === bold &&
308→             textEl.isItalic(j) === italic &&
309→             textEl.isUnderline(j) === underline &&
310→             textEl.isStrikethrough(j) === strikethrough &&
311→             textEl.getLinkUrl(j) === link) {
312→        j++;
313→      }
314→
315→      var chunk = this._escapeHtml(text.substring(i, j));
316→
317→      if (link) chunk = '<a href="' + this._escapeHtml(link) + '">' + chunk + '</a>';
318→      if (bold) chunk = '<strong>' + chunk + '</strong>';
319→      if (italic) chunk = '<em>' + chunk + '</em>';
320→      if (underline) chunk = '<u>' + chunk + '</u>';
321→      if (strikethrough) chunk = '<s>' + chunk + '</s>';
322→
323→      html += chunk;
324→      i = j;
325→    }
326→    return html;
327→  },
328→
329→  _escapeHtml: function (str) {
330→    return str
331→      .replace(/&/g, '&amp;')
332→      .replace(/</g, '&lt;')
333→      .replace(/>/g, '&gt;')
334→      .replace(/"/g, '&quot;');
335→  },
336→
337→  /**
338→   * Extract all inline images from the document body (excluding the metadata table).
339→   * Returns array of {blob, name, elementIndex, blobHash}.
340→   */
341→  getImages: function () {
342→    var doc = DocumentApp.getActiveDocument();
343→    var body = doc.getBody();
344→    var metaTable = this.findMetadataTable();
345→    var metaTableIndex = metaTable ? metaTable.tableIndex : -1;
346→
347→    var images = [];
348→    var numChildren = body.getNumChildren();
349→    var imgCount = 0;
350→
351→    for (var i = 0; i < numChildren; i++) {
352→      var child = body.getChild(i);
353→
354→      // Skip the metadata table
355→      if (i === metaTableIndex) continue;
356→
357→      this._collectImagesFromElement(child, images, imgCount);
358→    }
359→    return images;
360→  },
361→
362→  _collectImagesFromElement: function (element, images, counter) {
363→    var type = element.getType();
364→
365→    if (type === DocumentApp.ElementType.INLINE_IMAGE) {
366→      var blob = element.getBlob();
367→      var hash = this._hashBlob(blob);
368→      var name = element.getAltTitle() || ('image_' + images.length + '.' + this._getExtension(blob.getContentType()));
369→      images.push({ blob: blob, name: name, blobHash: hash });
370→    } else if (type === DocumentApp.ElementType.INLINE_DRAWING) {
371→      // Drawings don't have a direct blob export in Apps Script;
372→      // we can attempt to get them via the element if possible
373→      // This is a known limitation — we flag it.
374→      try {
375→        var blob = element.getBlob();
376→        if (blob) {
377→          var hash = this._hashBlob(blob);
378→          images.push({ blob: blob, name: 'drawing_' + images.length + '.png', blobHash: hash });
379→        }
380→      } catch (e) {
381→        // Drawings may not support getBlob; skip gracefully
382→      }
383→    }
384→
385→    // Recurse into containers (paragraphs, list items, table cells, etc.)
386→    if (typeof element.getNumChildren === 'function') {
387→      for (var c = 0; c < element.getNumChildren(); c++) {
388→        this._collectImagesFromElement(element.getChild(c), images, counter);
389→      }
390→    }
391→  },
392→
393→  _hashBlob: function (blob) {
394→    var bytes = blob.getBytes();
395→    var digest = Utilities.computeDigest(Utilities.DigestAlgorithm.MD5, bytes);
396→    return digest.map(function (b) {
397→      return ('0' + (b & 0xFF).toString(16)).slice(-2);
398→    }).join('');
399→  },
400→
401→  _getExtension: function (contentType) {
402→    var map = {
403→      'image/png': 'png',
404→      'image/jpeg': 'jpg',
405→      'image/gif': 'gif',
406→      'image/svg+xml': 'svg',
407→      'image/webp': 'webp'
408→    };
409→    return map[contentType] || 'png';
410→  }
411→};
412→

