  1→<!DOCTYPE html>
  2→<html>
  3→<head>
  4→<base target="_top">
  5→<style>
  6→  * { box-sizing: border-box; margin: 0; padding: 0; }
  7→  body { font-family: 'Google Sans', Roboto, Arial, sans-serif; font-size: 13px; color: #333; padding: 12px; }
  8→
  9→  /* Tabs */
 10→  .tabs { display: flex; border-bottom: 2px solid #e0e0e0; margin-bottom: 12px; }
 11→  .tab { flex: 1; text-align: center; padding: 8px 0; cursor: pointer; font-weight: 500; color: #666; border-bottom: 2px solid transparent; margin-bottom: -2px; }
 12→  .tab.active { color: #1a73e8; border-bottom-color: #1a73e8; }
 13→  .tab-content { display: none; }
 14→  .tab-content.active { display: block; }
 15→
 16→  /* Form elements */
 17→  label { display: block; font-weight: 500; margin: 8px 0 4px; color: #555; }
 18→  select, input[type="text"], input[type="password"] {
 19→    width: 100%; padding: 8px; border: 1px solid #dadce0; border-radius: 4px;
 20→    font-size: 13px; background: #fff;
 21→  }
 22→  select:focus, input:focus { outline: none; border-color: #1a73e8; }
 23→
 24→  /* Buttons */
 25→  .btn { display: inline-block; padding: 8px 16px; border: none; border-radius: 4px; font-size: 13px; cursor: pointer; font-weight: 500; }
 26→  .btn-primary { background: #1a73e8; color: #fff; width: 100%; }
 27→  .btn-primary:hover { background: #1557b0; }
 28→  .btn-primary:disabled { background: #ccc; cursor: not-allowed; }
 29→  .btn-secondary { background: #f1f3f4; color: #333; }
 30→  .btn-secondary:hover { background: #e0e0e0; }
 31→  .btn-sm { padding: 4px 10px; font-size: 12px; }
 32→
 33→  /* Toggle */
 34→  .toggle-group { display: flex; border: 1px solid #dadce0; border-radius: 4px; overflow: hidden; margin-top: 4px; }
 35→  .toggle-option { flex: 1; text-align: center; padding: 8px; cursor: pointer; font-size: 12px; font-weight: 500; background: #fff; border: none; }
 36→  .toggle-option.active { background: #1a73e8; color: #fff; }
 37→
 38→  /* Progress */
 39→  .progress-bar { width: 100%; height: 4px; background: #e0e0e0; border-radius: 2px; margin: 8px 0; display: none; }
 40→  .progress-bar .fill { height: 100%; background: #1a73e8; border-radius: 2px; transition: width 0.3s; width: 0%; }
 41→
 42→  /* Sync log */
 43→  .sync-log { margin-top: 12px; border-top: 1px solid #e0e0e0; padding-top: 8px; }
 44→  .sync-log h4 { font-size: 12px; color: #666; margin-bottom: 6px; }
 45→  .log-entry { font-size: 11px; padding: 4px 0; border-bottom: 1px solid #f1f3f4; }
 46→  .log-entry .status { font-weight: 600; }
 47→  .log-entry .status.success { color: #0d904f; }
 48→  .log-entry .status.partial { color: #e37400; }
 49→  .log-entry .status.error { color: #d93025; }
 50→  .log-entry .timestamp { color: #999; }
 51→  .log-entry .failures { color: #d93025; font-size: 10px; margin-top: 2px; }
 52→
 53→  /* Messages */
 54→  .msg { padding: 8px; border-radius: 4px; margin: 8px 0; font-size: 12px; }
 55→  .msg-info { background: #e8f0fe; color: #1a73e8; }
 56→  .msg-error { background: #fce8e6; color: #d93025; }
 57→  .msg-success { background: #e6f4ea; color: #0d904f; }
 58→  .msg-warn { background: #fef7e0; color: #e37400; }
 59→
 60→  /* Relationship lookup */
 61→  .lookup-group { display: flex; gap: 4px; margin-top: 4px; }
 62→  .lookup-group input { flex: 1; }
 63→  .lookup-results { max-height: 120px; overflow-y: auto; border: 1px solid #dadce0; border-radius: 4px; margin-top: 4px; display: none; }
 64→  .lookup-item { padding: 6px 8px; cursor: pointer; font-size: 12px; border-bottom: 1px solid #f1f3f4; }
 65→  .lookup-item:hover { background: #e8f0fe; }
 66→
 67→  .section { margin-bottom: 12px; }
 68→  .hidden { display: none; }
 69→
 70→  /* Loading overlay */
 71→  .loading-overlay {
 72→    position: fixed; top: 0; left: 0; right: 0; bottom: 0;
 73→    background: rgba(255,255,255,0.85); z-index: 100;
 74→    display: flex; flex-direction: column; align-items: center; justify-content: center;
 75→  }
 76→  .spinner { width: 28px; height: 28px; border: 3px solid #e0e0e0; border-top-color: #1a73e8;
 77→    border-radius: 50%; animation: spin 0.8s linear infinite; }
 78→  @keyframes spin { to { transform: rotate(360deg); } }
 79→  .loading-text { margin-top: 10px; font-size: 13px; color: #666; }
 80→</style>
 81→</head>
 82→<body>
 83→
