187→<script>
188→  var currentMode = 'SAVE';
189→  var currentContentTypeFields = [];
190→  var _pendingLoads = 0;
191→
192→  function startLoad() { _pendingLoads++; }
193→  function endLoad() {
194→    _pendingLoads--;
195→    if (_pendingLoads <= 0) {
196→      _pendingLoads = 0;
197→      var overlay = document.getElementById('loadingOverlay');
