391→
392→    fields.forEach(function(f) {
393→      if (!f.required) return;
394→      var ft = f.fieldType.toLowerCase();
395→
396→      // Select / Radio fields
397→      if (ft.indexOf('select') !== -1 || ft.indexOf('radio') !== -1) {
398→        var vals = (f.values || '').split(/\r?\n/).filter(function(v) { return v.trim(); });
399→        if (vals.length > 0) {
400→          hasSpecialFields = true;
401→          var wrapper = document.createElement('div');
402→          wrapper.style.marginBottom = '8px';
403→          wrapper.innerHTML = '<label style="margin:4px 0 2px;font-size:12px;">' + f.name + ' (' + f.variable + ')</label>';
404→          var sel = document.createElement('select');
