406→          sel.innerHTML = '<option value="">-- Select --</option>';
407→          vals.forEach(function(v) {
408→            // dotCMS values format can be "label|value" or just "value"
409→            var parts = v.trim().split('|');
410→            var label = parts[0].trim();
411→            var value = (parts[1] || parts[0]).trim();
412→            var opt = document.createElement('option');
