fireWorkflow: function (host, token, action, contentletData) {
  var endpoint = '/api/v1/workflow/actions/default/fire/' + action;
  var payload = { contentlet: contentletData };
  var resp = this._post(host, token, endpoint, payload);

  Logger.log('fireWorkflow raw response (first 1000): ' + JSON.stringify(resp).substring(0, 1000));

  var entity = resp.entity || {};

  // Shape 1: entity IS the contentlet — { entity: { identifier: "...", ... } }
  if (entity.identifier) return entity;

  // Shape 2: results array — { entity: { results: [{identifier: "..."}] } }
  if (entity.results && entity.results.length > 0) return entity.results[0];

  // Shape 3: inode-keyed — { entity: { "<inode>": { identifier: "..." } } }
  var keys = Object.keys(entity);
  for (var i = 0; i < keys.length; i++) {
    var val = entity[keys[i]];
    if (val && typeof val === 'object' && val.identifier) {
      return val;
    }
  }

  // Shape 4: entity is a string (some endpoints return just the inode)
  if (typeof resp.entity === 'string') {
    return { identifier: '', inode: resp.entity, _raw: 'entity was string: ' + resp.entity };
  }

  // Fallback — attach debug info
  entity._raw = JSON.stringify(resp).substring(0, 500);
  return entity;
},

