fireWorkflow: function (host, token, action, contentletData) {
  var endpoint = '/api/v1/workflow/actions/default/fire/' + action;
  var payload = { contentlet: contentletData };
  var resp = this._post(host, token, endpoint, payload);

  Logger.log('fireWorkflow raw keys: ' + JSON.stringify(Object.keys(resp)));

  // The response may or may not have an "entity" wrapper
  var entity = resp.entity || resp;

  Logger.log('entity type: ' + typeof entity + ', keys: ' + JSON.stringify(Object.keys(entity)));

  // Shape 1: entity IS the contentlet — { identifier: "...", ... }
  if (entity.identifier) return entity;

  // Shape 2: results array — { results: [{identifier: "..."}] }
  if (entity.results && entity.results.length > 0) return entity.results[0];

  // Shape 3: identifier-keyed — { "<identifier-uuid>": {contentlet object} }
  // Look for any key that is a UUID pattern and has an object value
  var uuidPattern = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  var keys = Object.keys(entity);
  for (var i = 0; i < keys.length; i++) {
    if (uuidPattern.test(keys[i]) && entity[keys[i]] && typeof entity[keys[i]] === 'object') {
      var contentlet = entity[keys[i]];
      contentlet.identifier = contentlet.identifier || keys[i];
      Logger.log('Found identifier from key: ' + keys[i]);
      return contentlet;
    }
  }

  // Last resort: just grab first object value
  for (var j = 0; j < keys.length; j++) {
    var val = entity[keys[j]];
    if (val && typeof val === 'object' && !Array.isArray(val)) {
      val.identifier = val.identifier || keys[j];
      return val;
    }
  }

  return entity;
},

