  fireWorkflow: function (host, token, action, contentletData) {
    var endpoint = '/api/v1/workflow/actions/default/fire/' + action;
    var payload = { contentlet: contentletData };
    var resp = this._post(host, token, endpoint, payload);
    var entity = resp.entity || {};

    // Shape 1: entity IS the contentlet — { identifier: "...", ... }
    if (entity.identifier) return entity;

    // Shape 2: results array — { results: [{identifier: "..."}] }
    if (entity.results && entity.results.length > 0) return entity.results[0];

    // Shape 3: identifier-keyed — { "<identifier>": {contentlet object} }
    // The key itself is the identifier; extract it and attach to the contentlet
    var keys = Object.keys(entity);
    for (var i = 0; i < keys.length; i++) {
      var val = entity[keys[i]];
      if (val !== null && typeof val === 'object' && !Array.isArray(val)) {
        val.identifier = val.identifier || keys[i];
        return val;
      }
    }

    return entity;
  },

  // ── HTTP helpers ──

  _get: function (host, token, path, params) {
    var url = host + path;
    if (params) {
      var qs = Object.keys(params).map(function (k) {
        return encodeURIComponent(k) + '=' + encodeURIComponent(params[k]);
      }).join('&');
      url += (url.indexOf('?') === -1 ? '?' : '&') + qs;
    }
    var options = {
      method: 'get',
      headers: { 'Authorization': 'Bearer ' + token },
      muteHttpExceptions: true
    };
    var response = UrlFetchApp.fetch(url, options);
    return JSON.parse(response.getContentText());
  },

  _post: function (host, token, path, payload) {
    var options = {
      method: 'post',
      contentType: 'application/json',
      headers: { 'Authorization': 'Bearer ' + token },
      payload: JSON.stringify(payload),
      muteHttpExceptions: true
    };
    var response = UrlFetchApp.fetch(host + path, options);
    return JSON.parse(response.getContentText());
  }
};

