/**
 * Generate or merge the metadata table.
 * If a table already exists, only add missing fields (preserving existing values).
 * If no table exists, create a new one.
 * Includes ALL editable fields, not just required ones.
 */
generateMetadataTable: function (fields) {
  var doc = DocumentApp.getActiveDocument();
  var body = doc.getBody();

  // Skip fields that are body/WYSIWYG (those go in the doc body, not the table)
  var editableFields = fields.filter(function (f) {
    var ft = f.fieldType.toLowerCase();
    return ft.indexOf('wysiwyg') === -1 && ft.indexOf('storyblock') === -1;
  });

  var existing = this.findMetadataTable();

  if (existing) {
    // Merge: add rows for fields not already in the table
    var table = existing.table;
    var existingVars = {};
    for (var r = 1; r < table.getNumRows(); r++) {
      var varName = table.getRow(r).getCell(0).getText().trim();
      if (varName) existingVars[varName] = true;
    }

    // Ensure system rows exist
    var systemFields = ['identifier', 'contentType', 'host', 'folder', 'languageId'];
    for (var s = 0; s < systemFields.length; s++) {
      if (!existingVars[systemFields[s]]) {
        var sRow = table.appendTableRow();
        sRow.appendTableCell(systemFields[s]);
        sRow.appendTableCell('');
        existingVars[systemFields[s]] = true;
      }
    }

    // Add missing editable fields
    for (var i = 0; i < editableFields.length; i++) {
      var ef = editableFields[i];
      if (!existingVars[ef.variable]) {
        var newRow = table.appendTableRow();
        newRow.appendTableCell(ef.variable);
        var valCell = newRow.appendTableCell('');
        this._applyDropdownHint(valCell, ef);
        existingVars[ef.variable] = true;
      }
    }
  } else {
    // Create new table
    var cells = this._buildTableCells(editableFields);
    var table = body.insertTable(0, cells);

    // Style header row
    var headerRow = table.getRow(0);
    headerRow.getCell(0).setText(this.MARKER_FIELD).setAttributes(this._boldStyle());
    headerRow.getCell(1).setText(this.MARKER_VALUE).setAttributes(this._boldStyle());

    // Apply dropdown hints to select/boolean fields
    // System fields are rows 1-5, editable fields start at row 6
    var editableStartRow = 6;
    for (var j = 0; j < editableFields.length; j++) {
      var rowIdx = editableStartRow + j;
      if (rowIdx < table.getNumRows()) {
        this._applyDropdownHint(table.getRow(rowIdx).getCell(1), editableFields[j]);
      }
    }

    // Insert a paragraph after the table for body content
    body.insertParagraph(1, '');
  }

  return editableFields;
},

