                     glyph === DocumentApp.GlyphType.LATIN_UPPER ||
                     glyph === DocumentApp.GlyphType.LATIN_LOWER ||
                     glyph === DocumentApp.GlyphType.ROMAN_UPPER ||
                     glyph === DocumentApp.GlyphType.ROMAN_LOWER);
