    var html = '<table>';
    for (var r = 0; r < table.getNumRows(); r++) {
      html += '<tr>';
      var row = table.getRow(r);
      for (var c = 0; c < row.getNumCells(); c++) {
        var cell = row.getCell(c);
        html += '<td>' + this._escapeHtml(cell.getText()) + '</td>';
      }
      html += '</tr>';
    }
    html += '</table>';
    return html;
