    if (!result) return;

    var table = result.table;
    for (var r = 1; r < table.getNumRows(); r++) {
      var row = table.getRow(r);
      if (row.getNumCells() < 2) continue;
      if (row.getCell(0).getText().trim() === fieldVariable) {
        var cell = row.getCell(1);
        cell.setText(value);
