      return ('0' + (b & 0xFF).toString(16)).slice(-2);
    }).join('');
  },

  _getExtension: function (contentType) {
    var map = {
      'image/png': 'png',
      'image/jpeg': 'jpg',
      'image/gif': 'gif',
      'image/svg+xml': 'svg',
      'image/webp': 'webp'
    };
    return map[contentType] || 'png';
  }
};

