function populateAddFieldDropdown(allFields) {
  var sel = document.getElementById('addFieldSelect');
  sel.innerHTML = '<option value="">-- Select a field --</option>';

  // Get fields currently in the metadata table
  google.script.run
    .withSuccessHandler(function(metaFields) {
