function loadContentTypes() {
  startLoad();
  google.script.run
    .withSuccessHandler(function(types) {
      var sel = document.getElementById('contentType');
      sel.innerHTML = '<option value="">-- Select --</option>';
      types.forEach(function(ct) {
        var opt = document.createElement('option');
        opt.value = ct.variable;
        opt.textContent = ct.name;
        sel.appendChild(opt);
      });
      // Auto-select content type from metadata table
      google.script.run
        .withSuccessHandler(function(fields) {
          if (!fields) { endLoad(); return; }
          var found = false;
          for (var i = 0; i < fields.length; i++) {
            if (fields[i].variable === 'contentType' && fields[i].value) {
              sel.value = fields[i].value;
              found = true;
              google.script.run
                .withSuccessHandler(function(ctFields) {
                  currentContentTypeFields = ctFields;
                  populateBodyFieldDropdown(ctFields);
                  buildFieldEditor(ctFields);
                  populateAddFieldDropdown(ctFields);
                  endLoad();
                })
                .withFailureHandler(function(e) { endLoad(); })
                .getContentTypeFields(fields[i].value);
              break;
            }
          }
          if (!found) endLoad();
        })
        .withFailureHandler(function(e) { endLoad(); })
        .getMetadataFields();
    })
    .withFailureHandler(function(e) { showMsg('sync-msg', 'Failed to load content types: ' + e.message, 'error'); endLoad(); })
    .getContentTypes();
}

