function loadContentTypes() {
  // Auto-detect content type from existing metadata table
  startLoad();
  google.script.run
    .withSuccessHandler(function(fields) {
      if (!fields) { endLoad(); return; }
      var found = false;
      for (var i = 0; i < fields.length; i++) {
        if (fields[i].variable === 'contentType' && fields[i].value) {
          var ctVar = fields[i].value;
          document.getElementById('contentType').value = ctVar;
          document.getElementById('ctSearch').value = ctVar;
          document.getElementById('ctSelected').style.display = 'block';
          document.getElementById('ctSelectedName').textContent = 'Selected: ' + ctVar;
          found = true;
          google.script.run
            .withSuccessHandler(function(ctFields) {
              currentContentTypeFields = ctFields;
              populateBodyFieldDropdown(ctFields);
              buildFieldEditor(ctFields);
              populateAddFieldDropdown(ctFields);
              endLoad();
            })
            .withFailureHandler(function(e) { endLoad(); })
            .getContentTypeFields(ctVar);
          // Also get host field var
          google.script.run
            .withSuccessHandler(function(hostVar) { currentHostFieldVar = hostVar; })
            .getHostFieldVar(ctVar);
          break;
        }
      }
      if (!found) endLoad();
    })
    .withFailureHandler(function(e) { endLoad(); })
    .getMetadataFields();
}

function searchContentTypes() {
  var query = document.getElementById('ctSearch').value.trim();
  var results = document.getElementById('ctResults');
  results.style.display = 'block';
  results.innerHTML = '<div style="padding:6px;color:#999;">Searching...</div>';

  google.script.run
    .withSuccessHandler(function(types) {
      results.innerHTML = '';
      if (!types || types.length === 0) {
        results.innerHTML = '<div style="padding:6px;color:#999;">No results found.</div>';
        return;
      }
      types.forEach(function(ct) {
        var div = document.createElement('div');
        div.className = 'lookup-item';
        div.textContent = ct.name + ' (' + ct.variable + ')';
        div.onclick = function() {
          selectContentType(ct.variable, ct.name);
          results.style.display = 'none';
        };
        results.appendChild(div);
      });
    })
    .withFailureHandler(function(e) {
      results.innerHTML = '<div style="padding:6px;color:#d93025;">Error: ' + e.message + '</div>';
    })
    .searchContentTypes(query);
}

function selectContentType(ctVar, ctName) {
  document.getElementById('contentType').value = ctVar;
  document.getElementById('ctSearch').value = '';
  document.getElementById('ctSelected').style.display = 'block';
  document.getElementById('ctSelectedName').textContent = 'Selected: ' + ctName + ' (' + ctVar + ')';
  generateTable(ctVar);
}

